<template><section class="page"><van-nav-bar title="账户详情" left-arrow @click-left="router.back()"/><div v-if="loading" class="state-card"><van-loading/></div><van-empty v-else-if="error" image="error" :description="error"><van-button @click="load">重试</van-button></van-empty><van-cell-group v-else-if="detail" inset><van-cell title="账户" :value="detail.name"/><van-cell title="类型" :value="detail.account_type"/><van-cell title="币种" :value="detail.currencies.join('、')"/><van-cell title="状态" :value="detail.is_active?'启用':'关闭'"/><van-cell v-for="balance in balances" :key="balance.currency" :title="`余额 ${balance.currency}`" :value="String(balance.amount)"/></van-cell-group></section></template>
<script setup lang="ts">import{onMounted,ref}from'vue';import{useRoute,useRouter}from'vue-router';import{accountsApi,type AccountDetail,type Balance}from'../../api/accounts';import type{ApiError}from'../../api/client';const route=useRoute(),router=useRouter(),detail=ref<AccountDetail|null>(null),balances=ref<Balance[]>([]),loading=ref(false),error=ref('');async function load(){loading.value=true;error.value='';try{const name=String(route.params.accountName);[detail.value,balances.value]=await Promise.all([accountsApi.getAccountDetail(name),accountsApi.getBalance(name)])}catch(reason){error.value=(reason as ApiError).message}finally{loading.value=false}}onMounted(load)</script>
